            // s=0: i is not selected. s=1: i is selected.

            const dp_linear = Array(n).fill(0).map(() => 
                Array(k + 1).fill(0).map(() => [MAX_COST, MAX_COST])
            );

            // Base Case i = 0
            dp_linear[0][0][0] = 0; // Don't select 0
            if (k >= 1) {
                dp_linear[0][1][1] = costs[0]; // Select 0
            }

            // Transitions i = 1 to N-1
            for (let i = 1; i < n; i++) {
                for (let j = 0; j <= k; j++) {
                    // Case s=0 (i is NOT selected)
                    // Can come from i-1 selected or not selected
                    dp_linear[i][j][0] = Math.min(
                        dp_linear[i-1][j][0],
                        dp_linear[i-1][j][1]
                    );

                    // Case s=1 (i IS selected)
                    // Must come from i-1 NOT selected (s=0)
                    if (j >= 1) {
                        const cost_i = costs[i];
                        dp_linear[i][j][1] = dp_linear[i-1][j-1][0] + cost_i;
                    }
                }
            }

            // 2. Apply cycle constraints by fixing node 0's state and running DP on 1..N-1
            // This avoids the need for the complex path/cycle DP structure, by forcing the boundary conditions.

