function solve(nums: number[], k: number): number {
    const n = nums.length;

    // If k=0, no operations needed.
    if (k === 0) {
        return 0;
    }

    // Maximum possible number of peaks in a cycle is floor(N/2).
    if (k > Math.floor(n / 2)) {
        return -1;
    }

    // Calculate the minimum cost to make each index i a peak, assuming its neighbors are NOT peaks
    // (which is true if we select k peaks such that no two are adjacent).
    const costs: number[] = new Array(n).fill(0);
    for (let i = 0; i < n; i++) {
        const prev = nums[(i - 1 + n) % n];
        const next = nums[(i + 1) % n];
        // Cost = max(0, required_value - current_value)
        // Required value = max(prev, next) + 1
        costs[i] = Math.max(0, Math.max(prev, next) + 1 - nums[i]);
    }

    const MAX_COST = 1e18; // Using a large number for infinity

    // The problem reduces to finding a minimum cost Independent Set of size k on a Cycle Graph.
    // We solve this by breaking the cycle at node 0 and running DP twice:
    // 1. Assume node 0 is NOT selected. (DP on path 1...N-1)
    // 2. Assume node 0 IS selected. (DP on path 1...N-1, with constraint that node N-1 must not be selected)

    let overallMinCost = MAX_COST;

    // --- Case A: Node 0 is NOT selected (s0=0) ---
    // We run DP on indices 1 to N-1, targeting k peaks.
    if (k <= n - 1) {
        // dp_A[i][j][s]: min cost considering indices 1..i, j peaks, state s at i.
        // s=0: i is not selected. s=1: i is selected.
        // We use size N to map 1..N-1 indices cleanly, but only use indices 1 onwards.
        const dp_A: number[][][] = Array(n).fill(0).map(() => 
            Array(k + 1).fill(0).map(() => [MAX_COST, MAX_COST])
        );

        // Base case i = 1
        dp_A[1][0][0] = 0; // 1 not selected
        if (k >= 1) {
            dp_A[1][1][1] = costs[1]; // 1 selected
        }

        // Transitions i = 2 to N-1
        for (let i = 2; i < n; i++) {
            for (let j = 0; j <= k; j++) {
                // Case s=0 (i is NOT selected)
                dp_A[i][j][0] = Math.min(
                    dp_A[i-1][j][0],
                    dp_A[i-1][j][1]
                );

                // Case s=1 (i IS selected)
                if (j >= 1) {
                    // Must come from i-1 NOT selected (s=0)
                    const cost_i = costs[i];
                    dp_A[i][j][1] = dp_A[i-1][j-1][0] + cost_i;
                }
            }
        }

        // Final Check for Case A: N-1 can be selected or not selected (since 0 is not selected).
        const costA = Math.min(
            dp_A[n - 1][k][0],
            dp_A[n - 1][k][1]
        );
        overallMinCost = Math.min(overallMinCost, costA);
    }


    // --- Case B: Node 0 IS selected (s0=1) ---
    // We run DP on indices 1 to N-1, targeting k-1 peaks. Constraint: Node N-1 must NOT be selected (s_N-1=0).
    if (k >= 1) {
        // dp_B[i][j][s]: min cost considering indices 1..i, j peaks, state s at i.
        const dp_B: number[][][] = Array(n).fill(0).map(() => 
            Array(k + 1).fill(0).map(() => [MAX_COST, MAX_COST])
        );

        // Base case i = 1: Must NOT be selected (because 0 is selected)
        dp_B[1][0][0] = 0; // 1 not selected
        // dp_B[1][1][1] remains MAX_COST

        // Transitions i = 2 to N-1
        for (let i = 2; i < n; i++) {
            for (let j = 0; j <= k; j++) {
                // Case s=0 (i is NOT selected)
                dp_B[i][j][0] = Math.min(
                    dp_B[i-1][j][0],
                    dp_B[i-1][j][1]
