                const dp_A = Array(n).fill(0).map(() => 
                    Array(k + 1).fill(0).map(() => [MAX_COST, MAX_COST])
                );

                // Base case i=1 (since 0 is fixed as non-selected)
                dp_A[1][0][0] = 0; // 1 not selected, cost 0
                if (k >= 1) {
                    dp_A[1][1][1] = costs[1]; // 1 selected, cost costs[1]
                }
                dp_A[1][1][0] = dp_A[0][1][0]; // Not possible, we must use i=1 base case.

                // Correct Base Case for segment [1, N-1] assuming 0 is NOT selected (i.e., 1 can be anything, but 0 is 0)
                const dp_A_fixed = Array(n).fill(0).map(() => 
                    Array(k + 1).fill(0).map(() => [MAX_COST, MAX_COST])
                );

                // Base case i=1
                dp_A_fixed[1][0][0] = 0; 
                dp_A_fixed[1][1][1] = costs[1];
                dp_A_fixed[1][0][1] = MAX_COST; // Cannot be selected if j=0

                // Transitions i = 2 to N-1
                for (let i = 2; i < n; i++) {
                    for (let j = 0; j <= k; j++) {
                        // Case s=0 (i is NOT selected)
                        dp_A_fixed[i][j][0] = Math.min(
                            dp_A_fixed[i-1][j][0],
                            dp_A_fixed[i-1][j][1]
                        );

                        // Case s=1 (i IS selected)
                        if (j >= 1) {
                            const cost_i = costs[i];
                            dp_A_fixed[i][j][1] = dp_A_fixed[i-1][j-1][0] + cost_i;
                        }
                    }
                }

                // Final Check for Case A: 0 is not selected, N-1 state matters for wrap around (N-1 must not be selected if 0 is selected, but 0 is not selected here).
                // The only wrap-around constraint is N-1 and 0. Since 0 is not selected, N-1 can be anything.
                const costA = Math.min(
                    dp_A_fixed[n - 1][k][0],
                    dp_A_fixed[n - 1][k][1]
                );
                overallMinCost = Math.min(overallMinCost, costA);
            }


            // Case B: Node 0 IS selected (s0=1)
            // Run linear DP on indices 1 to N-1, aiming for k-1 peaks (since 0 is one peak).
            if (k >= 1) {
                // Initialize DP for segment [1, N-1]
                const dp_B_fixed = Array(n).fill(0).map(() => 
                    Array(k + 1).fill(0).map(() => [MAX_COST, MAX_COST])
                );

                // Base case i=1: Must NOT be selected (because 0 is selected)
                dp_B_fixed[1][0][0] = 0; // 1 not selected, cost 0
                dp_B_fixed[1][1][1] = MAX_COST; // Cannot be selected if 0 is selected
                dp_B_fixed[1][0][1] = MAX_COST; 

                // Transitions i = 2 to N-1
                for (let i = 2; i < n; i++) {
                    for (let j = 0; j <= k; j++) {
                        // Case s=0 (i is NOT selected)
                        dp_B_fixed[i][j][0] = Math.min(
                            dp_B_fixed[i-1][j][0],
                            dp_B_fixed[i-1][j][1]
                        );

                        // Case s=1 (i IS selected)
                        if (j >= 1) {
                            const cost_i = costs[i];
                            dp_B_fixed[i][j][1] = dp_B_fixed[i-1][j-1][0] + cost_i;
                        }
                    }
                }

                // Final Check for Case B: 0 is selected (s0=1). Therefore, N-1 MUST NOT be selected (s_N-1=0).
                const costB = dp_B_fixed[n - 1][k - 1][0];
                overallMinCost = Math.min(overallMinCost, costB);
            }


            return overallMinCost === MAX_COST ? -1 : overallMinCost;
    }
}
